/**
 * scripts/seed-other-templates.mjs
 *
 * Generates reference templates (Restaurant, Café, Coiffeur, Beauté, Boutique)
 * for the template picker. Does NOT create any sites in the DB.
 *
 * Each template:
 *   - Is generated by Claude Opus (text-only prompt)
 *   - Gets a Playwright screenshot by rendering the code directly in a headless
 *     browser (no dev server required)
 *   - Is saved to reference_sites with react_code + screenshot_url
 *
 * Usage:
 *   node scripts/seed-other-templates.mjs
 *   node scripts/seed-other-templates.mjs --force
 *   node scripts/seed-other-templates.mjs --slug=tpl-restaurant-jardin
 *   node scripts/seed-other-templates.mjs --skip-screenshot   # save code only
 */

