// ── TypeScript annotation stripper ───────────────────────────────────────────
// Mirrors the same function in CodePreview.tsx and route.ts.
// Cleans generated code before saving so Babel React-only preset works.
function stripTypeScript(code) {
  return code
    .replace(/^import\s+type\b.+$/gm, '')
    .replace(/^(?:export\s+)?interface\s+\w+[^{]*\{[^{}]*\}/gm, '')
    .replace(/^(?:export\s+)?type\s+\w+\s*(?:<[^>]*>)?\s*=\s*.+;?\s*$/gm, '')
    .replace(/\}\s*:\s*\{[^{}]*\}/g, '}')
    .replace(/((?:const|let|var)\s+\w+)\s*:\s*[A-Za-z_$][\w$.<>[\]|& ,'"?!()]+?(?=\s*=(?!=))/g, '$1')
    .replace(/\b(\w+)\s*:\s*(?:React\.[\w.]+(?:<[^<>()]*>)?|[\w.]+(?:<[^<>()]*>)?(?:\[\])?(?:\s*\|\s*[\w.]+(?:<[^<>()]*>)?(?:\[\])?)*)\s*(?=[,)=])/g, '$1')
    .replace(/\b(\w+)\s*:\s*'[^']*'(?:\s*\|\s*(?:'[^']*'|"[^"]*"))+\s*(?=[,)=])/g, '$1')
    .replace(/\b(useState|useRef|useCallback|useMemo|useReducer|useContext|useLayoutEffect|useImperativeHandle|createRef|createContext)\s*<[^<>()[\]{}]+>/g, '$1')
}

// ── CDN URLs (same as /s/[id]/route.ts) ──────────────────────────────────────

const CDN = {
  react:       'https://esm.sh/react@18',
  jsxRuntime:  'https://esm.sh/react@18/jsx-runtime',
  reactDom:    'https://esm.sh/react-dom@18/client',
  lucide:      'https://esm.sh/lucide-react?deps=react@18',
}

// ── Build self-contained HTML for Playwright ──────────────────────────────────

function buildHtml(reactCode) {
  const escaped = JSON.stringify(stripTypeScript(reactCode))

  return `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>
  <script src="https://cdn.tailwindcss.com"></script>
  <link rel="preconnect" href="https://fonts.googleapis.com" />
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin="anonymous" />
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&family=Playfair+Display:wght@400;600;700;900&display=swap" rel="stylesheet" />
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    html { scroll-behavior: smooth; }
    body { margin: 0; background: #0f0f13; }
    [id] { scroll-margin-top: 80px; }
    @keyframes spin { to { transform: rotate(360deg) } }
    #loading { position:fixed;inset:0;background:#0f0f13;display:flex;align-items:center;justify-content:center;z-index:9999 }
  </style>
</head>
<body>
  <div id="loading">
    <div style="width:32px;height:32px;border:2px solid #7c3aed;border-top-color:transparent;border-radius:50%;animation:spin 0.8s linear infinite"></div>
  </div>
  <div id="root"></div>
  <script>
  (function(){
    var REACT = ${JSON.stringify(CDN.react)};
    var JSX_RUNTIME = ${JSON.stringify(CDN.jsxRuntime)};
    var REACT_DOM = ${JSON.stringify(CDN.reactDom)};
    var LUCIDE = ${JSON.stringify(CDN.lucide)};

    function run() {
      var code = ${escaped};
      var compiled;
      try {
        compiled = Babel.transform(code, {
          presets: [['react', { runtime: 'automatic' }]],
          filename: 'App.jsx',
        }).code;
      } catch(err) {
        document.getElementById('loading').remove();
        document.getElementById('root').innerHTML = '<pre style="color:#f87171;padding:24px;font-size:12px">' + err.message + '</pre>';
        return;
      }
      var js = compiled
        .replace(/export\\s+default\\s+(function|class)\\s+App\\b/, '$1 App')
        .replace(/from\\s+['"]react\\/jsx-runtime['"]/g, "from '" + JSX_RUNTIME + "'")
        .replace(/from\\s+['"]react['"]/g, "from '" + REACT + "'")
        .replace(/from\\s+['"]react-dom\\/client['"]/g, "from '" + REACT_DOM + "'")
        .replace(
          /^import\\s+\\{([^}]+)\\}\\s+from\\s+['"]lucide-react['"];?\\s*$/gm,
          function(_,names){ return "import * as _L from '" + LUCIDE + "';\\nconst {" + names.trim() + "} = new Proxy(_L,{get:(t,k)=>t[k]||(()=>null)});"; }
        )
        .replace(/^import\\s+.*?from\\s+['"][^h][^t][^t].*?['"];?\\s*$/gm, '');

      var src = [
        "import React from '" + REACT + "';",
        "import { createRoot } from '" + REACT_DOM + "';",
        js,
        "try{createRoot(document.getElementById('root')).render(React.createElement(App));}catch(e){console.error(e);}",
      ].join('\\n');
      var blob = new Blob([src],{type:'text/javascript'});
      var url = URL.createObjectURL(blob);
      var s = document.createElement('script');
      s.type = 'module'; s.src = url;
      s.onload = function(){ document.getElementById('loading').remove(); URL.revokeObjectURL(url); };
      document.body.appendChild(s);
    }

    if (window.Babel) { run(); }
    else { document.getElementById('babel-script') || document.querySelector('[src*="babel"]').addEventListener('load', run); }
  })();
  </script>
</body>
</html>`
}

// ── Generate code via Claude ───────────────────────────────────────────────────

async function generateCode(template) {
  console.log(`   🤖 Generating with Claude Opus…`)
  const response = await anthropic.messages.create({
    model:      'claude-opus-4-6',
    max_tokens: 9000,
    messages:   [{ role: 'user', content: template.prompt }],
  })

  let text = response.content.find(b => b.type === 'text')?.text ?? ''
  // Strip code fences if Claude added them anyway
  const fenced = text.match(/```(?:tsx?|jsx?)?\n([\s\S]+?)```/)
  if (fenced) text = fenced[1].trim()
  // Strip TypeScript annotations so Babel React-only preset compiles cleanly
  return stripTypeScript(text.trim())
}

// ── Playwright screenshot of in-memory HTML ───────────────────────────────────

async function takeScreenshot(html) {
  const { chromium } = await import('playwright')
  const browser = await chromium.launch({ headless: true })
  const page    = await browser.newPage()
  await page.setViewportSize({ width: 1440, height: 900 })

  await page.setContent(html, { waitUntil: 'networkidle' })

  // Wait for React to mount (loading overlay disappears)
  await page.waitForSelector('#loading', { state: 'detached', timeout: 25_000 }).catch(() => {})
  await page.waitForTimeout(2000) // settle animations

  const buffer = await page.screenshot({ type: 'png', fullPage: false })
  await browser.close()
  return buffer
}

// ── Upload screenshot to Supabase Storage ─────────────────────────────────────

async function uploadScreenshot(buffer, slug) {
  const storagePath = `templates/${slug}/hero.png`
  const { error } = await supabase.storage
    .from('sites')
    .upload(storagePath, buffer, { contentType: 'image/png', upsert: true })
  if (error) throw new Error(`Storage upload failed: ${error.message}`)
  const { data } = supabase.storage.from('sites').getPublicUrl(storagePath)
  return data.publicUrl
}

// ── Upsert reference_site (no backing site created) ──────────────────────────

async function upsertReferenceSite(template, code, screenshotUrl) {
  const { data: existing } = await supabase
    .from('reference_sites')
    .select('id')
    .eq('slug', template.slug)
    .single()

  const payload = {
    slug:           template.slug,
    name:           template.anonName,
    industry:       template.industry,
    url:            `${APP_URL}`,
    react_code:     code,
    site_type:      template.site_type,
    quality_score:  9,
    screenshot_url: screenshotUrl ?? null,
  }

  const { error } = existing
    ? await supabase.from('reference_sites').update(payload).eq('id', existing.id)
    : await supabase.from('reference_sites').insert(payload)

  if (error) throw new Error(error.message)
}

// ── Main ───────────────────────────────────────────────────────────────────────

async function main() {
  const force          = process.argv.includes('--force')
  const skipScreenshot = process.argv.includes('--skip-screenshot')
  const onlySlug       = process.argv.find(a => a.startsWith('--slug='))?.split('=')[1]
  const targets        = onlySlug ? TEMPLATES.filter(t => t.slug === onlySlug) : TEMPLATES

  if (targets.length === 0) {
    console.error('❌  No matching template for slug:', onlySlug)
    process.exit(1)
  }

  console.log(`🎨  Seeding ${targets.length} template(s)…\n`)

  for (const template of targets) {
    console.log(`\n━━ ${template.anonName} (${template.slug}) ━━`)

    // Skip if already complete
    const { data: existing } = await supabase
      .from('reference_sites')
      .select('id, react_code, screenshot_url')
      .eq('slug', template.slug)
      .single()

    if (existing?.react_code && existing?.screenshot_url && !force) {
      console.log(`   ⏭  Already complete — use --force to overwrite`)
      continue
    }

    // 1. Generate code
    let code
    try {
      code = existing?.react_code && !force ? existing.react_code : await generateCode(template)
      console.log(`   ✅ Code ready  lines=${code.split('\n').length}`)
    } catch (err) {
      console.error(`   ❌ Generation failed:`, err.message)
      continue
    }

    // 2. Screenshot
    let screenshotUrl = existing?.screenshot_url ?? null
    if (!skipScreenshot && (!screenshotUrl || force)) {
      try {
        console.log(`   📸 Rendering & screenshotting…`)
        const html   = buildHtml(code)
        const buffer = await takeScreenshot(html)
        screenshotUrl = await uploadScreenshot(buffer, template.slug)
        console.log(`   🖼  Screenshot uploaded → ${screenshotUrl}`)
      } catch (err) {
        console.warn(`   ⚠  Screenshot failed:`, err.message)
        console.warn(`   ℹ️  Template will be saved without screenshot`)
      }
    }

    // 3. Save to reference_sites
    try {
      await upsertReferenceSite(template, code, screenshotUrl)
      console.log(`   💾 Saved to reference_sites`)
    } catch (err) {
      console.error(`   ❌ reference_sites save failed:`, err.message)
    }
  }

  console.log('\n✅  Done!')
}

main().catch(err => { console.error(err); process.exit(1) })
